-- Withholding-tax compliance fields (AIT / VDS) on Bangladesh supplier payments.
-- Idempotent.

SET @db := DATABASE();

-- Supplier
SET @sql := (SELECT IF((SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA = @db AND TABLE_NAME = 'Supplier' AND COLUMN_NAME = 'tinNumber') > 0, 'SELECT 1', 'ALTER TABLE `Supplier` ADD COLUMN `tinNumber` VARCHAR(32) NULL'));
PREPARE s FROM @sql; EXECUTE s; DEALLOCATE PREPARE s;
