SET @sql := (SELECT IF((SELECT COUNT(*) FROM INFORMATION_SCHEMA.STATISTICS WHERE TABLE_SCHEMA = @db AND TABLE_NAME = 'Supplier' AND INDEX_NAME = 'Supplier_branchId_taxCategory_idx') > 0, 'SELECT 1', 'CREATE INDEX `Supplier_branchId_taxCategory_idx` ON `Supplier` (`branchId`, `taxCategory`)'));
PREPARE s FROM @sql; EXECUTE s; DEALLOCATE PREPARE s;

